using System;
using System.Data.SqlClient;
using Microsoft.Extensions.Configuration;
using System.IO;

public class DatabaseConnectionHelper
{
    private readonly string _connectionString;

    public DatabaseConnectionHelper()
    {
        var configuration = new ConfigurationBuilder()
            .SetBasePath(Directory.GetCurrentDirectory())
            .AddJsonFile("appsettings.json", optional: true)
            .AddEnvironmentVariables()
            .AddUserSecrets<DatabaseConnectionHelper>(optional: true)
            .Build();

        _connectionString = configuration.GetConnectionString("DefaultConnection") 
            ?? GetDefaultConnectionString();
    }

    public DatabaseConnectionHelper(IConfiguration configuration)
    {
        _connectionString = configuration.GetConnectionString("DefaultConnection")
            ?? GetDefaultConnectionString();
    }

    private string GetDefaultConnectionString()
    {
        var server = Environment.GetEnvironmentVariable("DB_SERVER") ?? "localhost";
        var database = Environment.GetEnvironmentVariable("DB_NAME") ?? "HackathonDB";
        var userId = Environment.GetEnvironmentVariable("DB_USER") ?? "sa";
        var password = Environment.GetEnvironmentVariable("DB_PASSWORD");

        if (string.IsNullOrEmpty(password))
        {
            throw new InvalidOperationException(
                "Database password not configured. Please set DB_PASSWORD environment variable or configure ConnectionStrings:DefaultConnection in appsettings.json");
        }

        return $"Server={server};Database={database};User Id={userId};Password={password};";
    }

    public SqlConnection GetConnection()
    {
        return new SqlConnection(_connectionString);
    }

    public SqlConnection GetOpenConnection()
    {
        var connection = new SqlConnection(_connectionString);
        connection.Open();
        return connection;
    }

    public bool TestConnection()
    {
        try
        {
            using (var connection = GetOpenConnection())
            {
                return connection.State == System.Data.ConnectionState.Open;
            }
        }
        catch
        {
            return false;
        }
    }
}